// API helper module for React frontend.
// Uses Fetch API with credentials included to support session cookies.

const API_BASE_URL = process.env.REACT_APP_API_BASE_URL || 'http://localhost:5914';

async function request(path, options = {}) {
  const headers = options.headers || {};
  const token = localStorage.getItem('access_token');
  if (token) {
    headers['Authorization'] = `Bearer ${token}`;
  }
  // Only set Content-Type for JSON bodies (skip for FormData)
  if (!(options.body instanceof FormData)) {
    headers['Content-Type'] = 'application/json';
  }

  const response = await fetch(`${API_BASE_URL}${path}`, {
    ...options,
    headers,
    credentials: 'include', // important for sending cookies
    body:
      options.body instanceof FormData
        ? options.body
        : options.body
        ? JSON.stringify(options.body)
        : undefined,
  });

  const contentType = response.headers.get('content-type') || '';
  if (!response.ok) {
    // Try to parse error message
    let errorText;
    try {
      errorText = await response.text();
    } catch (e) {
      errorText = `HTTP ${response.status}`;
    }
    throw new Error(errorText || `HTTP ${response.status}`);
  }
  if (contentType.includes('application/json')) {
    return await response.json();
  }
  return await response.text();
}

const api = {
  get: (path) => request(path, { method: 'GET' }),
  post: (path, body) => request(path, { method: 'POST', body }),
  put: (path, body) => request(path, { method: 'PUT', body }),
  delete: (path) => request(path, { method: 'DELETE' }),
};

export default api;
